/**
 * Writes auto-generated release notes (git history) under ./release-notes.
 *
 * Usage:
 *   node scripts/generate-release-notes.js
 *   node scripts/generate-release-notes.js --out release-notes/custom.md
 *   node scripts/generate-release-notes.js --since-tag v1.0.0
 *   node scripts/generate-release-notes.js --all
 */

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const root = path.join(__dirname, '..');

function sh(cmd, allowFail = false) {
  try {
    return execSync(cmd, { encoding: 'utf8', cwd: root, stdio: ['pipe', 'pipe', 'pipe'] }).trim();
  } catch (e) {
    if (allowFail) return '';
    throw e;
  }
}

function parseArgs(argv) {
  const out = { output: path.join(root, 'release-notes', 'latest.md'), sinceTag: null, all: false };
  for (let i = 2; i < argv.length; i += 1) {
    const a = argv[i];
    if (a === '--out' && argv[i + 1]) {
      out.output = path.isAbsolute(argv[i + 1]) ? argv[i + 1] : path.join(root, argv[i + 1]);
      i += 1;
    } else if (a === '--since-tag' && argv[i + 1]) {
      out.sinceTag = argv[i + 1];
      i += 1;
    } else if (a === '--all') {
      out.all = true;
    }
  }
  return out;
}

/** Latest `vmajor.minor.patch` tag (excludes legacy `v1.0.0-bN` style); falls back to `git describe`. */
function latestTag() {
  const list = sh('git tag -l "v*" --merged HEAD --sort=-v:refname', true)
    .split(/\r?\n/)
    .map((t) => t.trim())
    .filter(Boolean);
  const semverTag = list.find((t) => /^v\d+\.\d+\.\d+$/.test(t));
  if (semverTag) return semverTag;
  return sh('git describe --tags --abbrev=0', true);
}

function readJson(rel) {
  const p = path.join(root, rel);
  if (!fs.existsSync(p)) return null;
  return JSON.parse(fs.readFileSync(p, 'utf8'));
}

function main() {
  const opts = parseArgs(process.argv);
  const pkg = readJson('package.json') || {};
  const version = String(pkg.version || '0.0.0').trim();
  const productName =
    pkg.build && pkg.build.productName ? String(pkg.build.productName) : String(pkg.name || 'App');
  const shortSha = sh('git rev-parse --short HEAD', true) || 'unknown';
  const fullSha = sh('git rev-parse HEAD', true) || 'unknown';
  const branch = sh('git rev-parse --abbrev-ref HEAD', true) || 'unknown';
  const generatedAt = new Date().toISOString();

  let rangeForGit = '';
  let sinceLabel = '';
  if (opts.all) {
    sinceLabel = 'full repository history';
    rangeForGit = '';
  } else if (opts.sinceTag) {
    rangeForGit = `${opts.sinceTag}..HEAD`;
    sinceLabel = `commits since \`${opts.sinceTag}\``;
  } else {
    const tag = latestTag();
    if (tag) {
      rangeForGit = `${tag}..HEAD`;
      sinceLabel = `commits since tag \`${tag}\``;
    } else {
      sinceLabel = 'all commits (no prior git tag found)';
      rangeForGit = '';
    }
  }

  const logCmd = rangeForGit
    ? `git log ${rangeForGit} --pretty=format:%h%x09%s`
    : 'git log --pretty=format:%h%x09%s';
  const logLines = sh(logCmd, true)
    .split('\n')
    .map((l) => l.trim())
    .filter(Boolean);

  const shortlogCmd = rangeForGit ? `git shortlog -sn ${rangeForGit}` : 'git shortlog -sn HEAD';
  const shortlog = sh(shortlogCmd, true);

  const lines = [];
  lines.push(`# ${productName} — generated release notes`);
  lines.push('');
  lines.push('_This file is generated by `npm run release-notes`. Do not edit by hand._');
  lines.push('');
  lines.push('| Field | Value |');
  lines.push('| --- | --- |');
  lines.push(`| Package version | \`${version}\` (tag \`v${version}\`) |`);
  lines.push(`| Git | \`${shortSha}\` on \`${branch}\` |`);
  lines.push(`| Generated (UTC) | \`${generatedAt}\` |`);
  lines.push('');
  lines.push('## Summary');
  lines.push('');
  lines.push(`Source: **${sinceLabel}**.`);
  if (rangeForGit && logLines.length === 0) {
    lines.push('');
    lines.push(
      '_There are no new commits in this range (HEAD matches or is not ahead of the baseline)._'
    );
  } else if (logLines.length) {
    lines.push(`**${logLines.length}** commit(s).`);
  }
  lines.push('');
  lines.push('## Commits');
  lines.push('');
  if (logLines.length === 0) {
    lines.push('_(none)_');
  } else {
    logLines.forEach((row) => {
      const tab = row.indexOf('\t');
      const hash = tab >= 0 ? row.slice(0, tab) : row;
      const subj = tab >= 0 ? row.slice(tab + 1) : '';
      lines.push(`- \`${hash}\` ${subj}`);
    });
  }
  lines.push('');
  lines.push('## Committers');
  lines.push('');
  if (!shortlog || !shortlog.trim()) {
    lines.push('_(none in range)_');
  } else {
    shortlog.split('\n').forEach((l) => {
      const t = l.trim();
      if (t) lines.push(`- ${t}`);
    });
  }
  lines.push('');
  lines.push('## Full revision');
  lines.push('');
  lines.push('```');
  lines.push(fullSha);
  lines.push('```');
  lines.push('');

  const dir = path.dirname(opts.output);
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(opts.output, lines.join('\n'), 'utf8');
  process.stdout.write(`${opts.output}\n`);
}

main();
